try {
  const ast = parse(code, { modern: false }) as { html?: unknown };
  const root = ast.html;
  if (!root) return code;

  walkLegacySvelteNode(root, (node) => {
    if (node.type === "InlineComponent" && typeof node.name === "string") {
      if (isIconName(node.name)) icons.add(node.name);
      else inlineComponents.add(node.name);
    } else if (node.type === "MustacheTag") {
      const expr = node.expression as
        | { type?: string; name?: string }
        | undefined;
      if (expr?.type === "Identifier" && expr.name && isIconName(expr.name)) {
        icons.add(expr.name);
      }
    } else if (node.type === "Action" && typeof node.name === "string") {
      actions.add(node.name);
    }
  });
} catch {
  return code;
}

if (selectedComponents.size === 0) {
	const components = await p.multiselect({
		message: `Which ${highlight("components")} would you like to add?`,
		maxItems: 10,
		options: uiOnly.map((item) => {
			let deps = [...(item.registryDependencies ?? [])];
			if (options.deps) {
				deps = deps.concat(item.dependencies ?? []).concat(item.devDependencies ?? []);
			}
			return {
				label: item.name,
				value: item.name,
				hint: deps.length ? `also adds: ${deps.join(", ")}` : undefined,
			};
		}),
	});

	if (p.isCancel(components)) cancel();
	selectedComponents = new Set(components);
} else {
	const prettyList = prettifyList(Array.from(selectedComponents));
	p.log.step(`Components to install:\n${color.gray(prettyList)}`);
}

if (existingConfig) {
	tsconfig = cliConfig.resolveTSConfig(cwd, existingConfig);
} else {
	if (!tsconfigPath) {
		const input = await p.text({
			message: `Where is your ${highlight("tsconfig/jsconfig")} file?`,
			// initialValue: "tsconfig.json",
			placeholder: "tsconfig.json",
			validate: (value) => {
				const tsconfigPath = path.resolve(cwd, value ?? "");
				if (value && existsSync(tsconfigPath)) {
					return;
				}
				return `"${color.bold(value)}" does not exist. Please enter a valid path.`;
			},
		});

		if (p.isCancel(input)) cancel();

		config.typescript = { config: input };
	} else {
		config.typescript = tsconfigPath.includes("tsconfig");
	}

	tsconfig = cliConfig.resolveTSConfig(cwd, config);
}

return makeElement(name('scrollbar'), {
	stores: [scrollbarState.sizes, rootState.options.dir, scrollbarState.isVisible],
	returned: ([$sizes, $dir, $isVisible]) => {
		return {
			style: styleToString({
				position: 'absolute',
				bottom: 0,
				left: $dir === 'rtl' ? 'var(--melt-scroll-area-corner-width)' : 0,
				right: $dir === 'ltr' ? 'var(--melt-scroll-area-corner-width)' : 0,
				'--melt-scroll-area-thumb-width': `${getThumbSize($sizes)}px`,
				visibility: !$isVisible ? 'hidden' : undefined,
			}),
			'data-state': $isVisible ? 'visible' : 'hidden',
		};
	},
	action: (node: HTMLElement): MeltActionReturn<ScrollAreaEvents['scrollbar']> => {
		const unsubAction = action(node)?.destroy;
		rootState.scrollbarXEl.set(node);
		rootState.scrollbarXEnabled.set(true);
		return {
			destroy() {
				unsubAction?.();
				rootState.scrollbarXEl.set(null);
			},
		};
	},
});

return makeElement(name('scrollbar'), {
	stores: [scrollbarState.sizes, rootState.options.dir, scrollbarState.isVisible],
	returned: ([$sizes, $dir, $isVisible]) => {
		return {
			style: styleToString({
				position: 'absolute',
				top: 0,
				right: $dir === 'ltr' ? 0 : undefined,
				left: $dir === 'rtl' ? 0 : undefined,
				bottom: 'var(--melt-scroll-area-corner-height)',
				'--melt-scroll-area-thumb-height': `${getThumbSize($sizes)}px`,
				visibility: !$isVisible ? 'hidden' : undefined,
			}),
			'data-state': $isVisible ? 'visible' : 'hidden',
		};
	},
	action: (node: HTMLElement): MeltActionReturn<ScrollAreaEvents['scrollbar']> => {
		const unsubAction = action(node)?.destroy;
		rootState.scrollbarYEl.set(node);
		rootState.scrollbarYEnabled.set(true);
		return {
			destroy() {
				unsubAction?.();
				rootState.scrollbarYEl.set(null);
			},
		};
	},
});

if (priority <= options.preload_data) {
	current_a = { element: a, href: a.href };
	// we don't want to preload data again on tap if we've already preloaded it on hover
	current_priority = PRELOAD_PRIORITIES.tap;

	const intent = await get_navigation_intent(url, false);
	if (!intent) return;

	if (DEV) {
		void _preload_data(intent).then((result) => {
			if (result.type === 'loaded' && result.state.error) {
				console.warn(
					`Preloading data for ${intent.url.pathname} failed with the following error: ${result.state.error.message}\n` +
						'If this error is transient, you can ignore it. Otherwise, consider disabling preloading for this route. ' +
						'This route was preloaded due to a data-sveltekit-preload-data attribute. ' +
						'See https://svelte.dev/docs/kit/link-options for more info'
				);
			}
		});
	} else {
		void _preload_data(intent);
	}
} else if (priority <= options.preload_code) {
	current_a = { element: a, href: a.href };
	current_priority = priority;
	void _preload_code(/** @type {URL} */ (url));
}

for await (const node of read_ndjson(reader)) {
	if (node.type === 'redirect') {
		return resolve(node);
	}

	if (node.type === 'data') {
		// This is the first (and possibly only, if no pending promises) chunk
		node.nodes?.forEach((/** @type {any} */ node) => {
			if (node?.type === 'data') {
				node.uses = deserialize_uses(node.uses);
				node.data = deserialize(node.data);
			}
		});

		resolve(node);
	} else if (node.type === 'chunk') {
		// This is a subsequent chunk containing deferred data
		const { id, data, error } = node;
		const deferred = /** @type {import('types').Deferred} */ (deferreds.get(id));
		deferreds.delete(id);

		if (error) {
			deferred.reject(deserialize(error));
		} else {
			deferred.fulfil(deserialize(data));
		}
	}
}

if (include_load_functions) {
	const prev_state = page.state;
	const navigation_result = intent && (await load_route(intent));
	if (!navigation_result || nav_token !== token) return;

	if (navigation_result.type === 'redirect') {
		return _goto(
			new URL(navigation_result.location, current.url).href,
			{ replaceState: true },
			1,
			nav_token
		);
	}

	// This is a bit hacky but allows us not having to pass that boolean around, making things harder to reason about
	if (!reset_page_state) {
		navigation_result.props.page.state = prev_state;
	}
	update(navigation_result.props.page);
	current = { ...navigation_result.state, nav: current.nav };
	reset_invalidation();
	root.$set(navigation_result.props);
} else {
	reset_invalidation();
}

if (errors && __SVELTEKIT_EXPERIMENTAL_USE_TRANSFORM_ERROR__) {
	let last_idx = -1;
	result.props.errors = await Promise.all(
		// eslint-disable-next-line @typescript-eslint/await-thenable
		branch
			.map((b, i) => {
				if (i === 0) return undefined; // root layout wraps root error component, not the other way around
				if (!b) return null;

				i--;
				// Find the closest error component up to the previous branch
				while (i > last_idx + 1 && !errors[i]) i -= 1;
				last_idx = i;
				return errors[i]?.()
					.then((e) => e.component)
					.catch(() => undefined);
			})
			// filter out indexes where there was no branch, but keep indexes where there was a branch but no error component
			.filter((e) => e !== null)
	);
}

const result = await record_span({
	name: 'sveltekit.load',
	attributes: {
		'sveltekit.load.node_id': node.universal_id || 'unknown',
		'sveltekit.load.node_type': get_node_type(node.universal_id),
		'sveltekit.load.environment': 'server',
		'http.route': event.route.id || 'unknown'
	},
	fn: async (current) => {
		const traced_event = merge_tracing(event, current);
		const child_state = { ...event_state, is_in_universal_load: true };

		return await with_request_store({ event: traced_event, state: child_state }, () =>
			load.call(null, {
				url: event.url,
				params: event.params,
				data: server_data_node?.data ?? null,
				route: event.route,
				fetch: create_universal_fetch(event, state, fetched, csr, resolve_opts),
				setHeaders: event.setHeaders,
				depends: noop,
				parent,
				untrack: (fn) => fn(),
				tracing: traced_event.tracing
			})
		);
	}
});

for (const diagnostic of diagnostics) {
    if (
        diagnostic.range.start.line < 0 ||
        diagnostic.range.end.line < 0 ||
        (diagnostic.code !== DiagnosticCode.CANNOT_FIND_NAME &&
            diagnostic.code !== DiagnosticCode.CANNOT_FIND_NAME_X_DID_YOU_MEAN_Y)
    ) {
        continue;
    }
    const identifier = this.findIdentifierForDiagnostic(tsDoc, diagnostic, sourceFile);
    const name = identifier?.text;
    if (!name || names.has(name)) {
        continue;
    }

    if (name.startsWith('$')) {
        names.add(name.slice(1));
    } else if (!isInScript(diagnostic.range.start, document)) {
        if (this.isComponentStartTag(identifier)) {
            names.add(toGeneratedSvelteComponentName(name));
        }
    }
}

for (const edit of groups) {
    if (edit.newText) {
        continue;
    }
    const range = edit.range;
    const lineContentBeforeRemove = document.getText({
        start: { line: range.start.line, character: 0 },
        end: range.start
    });

    const onlyIndentLeft = !lineContentBeforeRemove.trim();
    if (!onlyIndentLeft) {
        continue;
    }

    const lineContentAfterRemove = document.getText({
        start: range.end,
        end: { line: range.end.line, character: Number.MAX_VALUE }
    });
    const emptyAfterRemove =
        !lineContentAfterRemove.trim() || lineContentAfterRemove.startsWith('</script>');
    if (emptyAfterRemove) {
        change.edits.push({
            range: { start: { line: range.start.line, character: 0 }, end: range.start },
            newText: ''
        });
    }
}

if (
    diagnostic.code === DiagnosticCode.ARG_TYPE_X_NOT_ASSIGNABLE_TO_TYPE_Y &&
    diagnostic.message.includes('ConstructorOfATypedSvelteComponent')
) {
    return {
        ...diagnostic,
        message:
            diagnostic.message +
            '\n\nPossible causes:\n' +
            '- You use the instance type of a component where you should use the constructor type\n' +
            '- Type definitions are missing for this Svelte Component. ' +
            (isSvelte5Plus
                ? ''
                : 'If you are using Svelte 3.31+, use SvelteComponentTyped to add a definition:\n' +
                  '  import type { SvelteComponentTyped } from "svelte";\n' +
                  '  class ComponentName extends SvelteComponentTyped<{propertyName: string;}> {}')
    };
}

for (const key in pkg.exports) {
	// special cases
	if (key === './compiler') continue;
	if (key === './internal') continue;
	if (key === './internal/disclose-version') continue;
	if (key === './internal/flags/legacy') continue;
	if (key === './internal/flags/tracing') continue;

	for (const type of ['browser', 'default']) {
		if (!pkg.exports[key][type]) continue;

		const subpackage = path.join(pkg.name, key);
		const resolved = path.resolve(pkg.exports[key][type]);
		const code = await bundle_code(`import ${JSON.stringify(resolved)}`);

		if (code === '') {
			// eslint-disable-next-line no-console
			console.error(`✅ ${subpackage} (${type})`);
		} else {
			// eslint-disable-next-line no-console
			console.error(code);
			// eslint-disable-next-line no-console
			console.error(`❌ ${subpackage} (${type})`);
			failed = true;
		}
	}
}

const built = await rollup({
	input: '__entry__',
	plugins: [
		virtual({ __entry__: entry_code }),
		{
			name: 'resolve-svelte',
			resolveId(id: string) {
				if (id.startsWith('svelte')) {
					const entry = pkg.exports[id.replace('svelte', '.')];
					if (!entry) return;
					if (typeof entry === 'string') return path.resolve(pkg_dir, entry);
					const file = entry.browser ?? entry.default;
					if (file) return path.resolve(pkg_dir, file);
				}
			}
		},
		nodeResolve({ exportConditions: ['production', 'import', 'browser', 'default'] })
	],
	// Treat optional peers / Node-only branches as external so we only scan
	// code that actually runs in the browser.
	external: ['esm-env'],
	onwarn: options.silent
		? () => {}
		: (warning, handler) => {
				if (warning.code === 'CIRCULAR_DEPENDENCY') return;
				handler(warning);
			}
});

for (const match of node.data.matchAll(regex_bidirectional_control_characters)) {
	let is_ignored = false;

	// if we have a svelte-ignore comment earlier in the text, bail
	// (otherwise we can only use svelte-ignore on parent elements/blocks)
	if (parent.type === 'Fragment') {
		for (const child of parent.nodes) {
			if (child === node) break;

			if (child.type === 'Comment') {
				is_ignored ||= extract_svelte_ignore(
					child.start + 4,
					child.data,
					context.state.analysis.runes
				).includes('bidirectional_control_characters');
			}
		}
	}

	if (!is_ignored) {
		let start = match.index + node.start;
		w.bidirectional_control_characters({ start, end: start + match[0].length });
	}
}

const component_returned_object = analysis.exports.flatMap(({ name, alias }) => {
	const binding = instance_state.scope.get(name);
	const expression = build_getter(b.id(name), instance_state);
	const getter = b.get(alias ?? name, [b.return(expression)]);

	if (expression.type === 'Identifier') {
		if (binding?.declaration_kind === 'let' || binding?.declaration_kind === 'var') {
			return [
				getter,
				b.set(alias ?? name, [b.stmt(b.assignment('=', expression, b.id('$$value')))])
			];
		} else if (!dev) {
			return b.init(alias ?? name, expression);
		}
	}

	if (binding?.kind === 'prop' || binding?.kind === 'bindable_prop') {
		return [getter, b.set(alias ?? name, [b.stmt(b.call(name, b.id('$$value')))])];
	}

	if (binding?.kind === 'state' || binding?.kind === 'raw_state') {
		const value = binding.kind === 'state' ? b.call('$.proxy', b.id('$$value')) : b.id('$$value');
		return [getter, b.set(alias ?? name, [b.stmt(b.call('$.set', b.id(name), value))])];
	}

	return getter;
});

if (
	dev &&
	node.callee.type === 'MemberExpression' &&
	node.callee.object.type === 'Identifier' &&
	node.callee.object.name === 'console' &&
	context.state.scope.get('console') === null &&
	node.callee.property.type === 'Identifier' &&
	['debug', 'dir', 'error', 'group', 'groupCollapsed', 'info', 'log', 'trace', 'warn'].includes(
		node.callee.property.name
	) &&
	node.arguments.some(
		(arg) => arg.type === 'SpreadElement' || context.state.scope.evaluate(arg).has_unknown
	)
) {
	return b.call(
		node.callee,
		b.spread(
			b.call(
				'$.log_if_contains_state',
				b.literal(node.callee.property.name),
				.../** @type {Expression[]} */ (node.arguments.map((arg) => context.visit(arg)))
			)
		)
	);
}

if (Object.keys(custom_css_props).length > 0) {
	if (context.state.metadata.namespace === 'svg') {
		// this boils down to <g><!></g>
		context.state.template.push_element('g', node.start, false);
	} else {
		// this boils down to <svelte-css-wrapper style='display: contents'><!></svelte-css-wrapper>
		context.state.template.push_element('svelte-css-wrapper', node.start, false);
		context.state.template.set_prop('style', 'display: contents');
	}

	context.state.template.push_comment();
	context.state.template.pop_element();

	statements.push(
		b.stmt(b.call('$.css_props', anchor, b.thunk(b.object(custom_css_props)))),
		b.stmt(fn(b.member(anchor, 'lastChild'))),
		b.stmt(b.call('$.reset', anchor))
	);
} else {
	context.state.template.push_comment();

	statements.push(add_svelte_meta(fn(anchor), node, 'component', { componentTag: node.name }));
}

for (const attribute of node.attributes) {
	if (attribute.type === 'SpreadAttribute') {
		spreads.push(b.thunk(/** @type {Expression} */ (context.visit(attribute))));
	} else if (attribute.type === 'Attribute') {
		const { value, has_state } = build_attribute_value(
			attribute.value,
			context,
			(value, metadata) =>
				metadata.has_call || metadata.has_await
					? b.call('$.get', memoizer.add(value, metadata))
					: value
		);

		if (attribute.name === 'name') {
			name = /** @type {Literal} */ (value);
		} else if (attribute.name !== 'slot') {
			if (has_state) {
				props.push(b.get(attribute.name, [b.return(value)]));
			} else {
				props.push(b.init(attribute.name, value));
			}
		}
	} else if (attribute.type === 'LetDirective') {
		context.visit(attribute, { ...context.state, let_directives: lets });
	}
}

for (const attribute of node.attributes) {
	if (attribute.type === 'Attribute') {
		if (attribute.name === 'xmlns' && !is_text_attribute(attribute)) {
			dynamic_namespace = attribute.value;
		}
		attributes.push(attribute);
	} else if (attribute.type === 'SpreadAttribute') {
		attributes.push(attribute);
	} else if (attribute.type === 'ClassDirective') {
		class_directives.push(attribute);
	} else if (attribute.type === 'StyleDirective') {
		style_directives.push(attribute);
	} else if (attribute.type === 'LetDirective') {
		statements.push(/** @type {ExpressionStatement} */ (context.visit(attribute)));
	} else if (attribute.type === 'OnDirective') {
		const handler = /** @type {Expression} */ (context.visit(attribute, inner_context.state));
		inner_context.state.after_update.push(b.stmt(handler));
	} else {
		context.visit(attribute, inner_context.state);
	}
}

for (const node of nodes) {
	if (node.type === 'ExpressionTag' && node.metadata.expression.is_async()) {
		flush();

		const expression = /** @type {Expression} */ (visit(node.expression));

		let call = b.call(
			'$$renderer.push',
			b.thunk(b.call('$.escape', expression), node.metadata.expression.has_await)
		);

		const blockers = node.metadata.expression.blockers();

		if (blockers.elements.length > 0) {
			call = b.call('$$renderer.async', blockers, b.arrow([b.id('$$renderer')], call));
		}

		state.template.push(b.stmt(call));
	} else if (node.type === 'Text' || node.type === 'Comment' || node.type === 'ExpressionTag') {
		sequence.push(node);
	} else {
		flush();
		visit(node, { ...state });
	}
}

block(() => {
		var component = get_component() ?? null;

		if (hydrating) {
			var data = read_hydration_instruction(/** @type {TemplateNode} */ (hydration_start_node));

			var server_had_component = data === HYDRATION_START;
			var client_has_component = component !== null;

			if (server_had_component !== client_has_component) {
				// Hydration mismatch: skip the server-rendered nodes and render fresh
				var anchor = skip_nodes();

				set_hydrate_node(anchor);
				branches.anchor = anchor;

				set_hydrating(false);
				branches.ensure(component, component && ((target) => render_fn(target, component)));
				set_hydrating(true);

				return;
			}
		}

		branches.ensure(component, component && ((target) => render_fn(target, component)));
	}, EFFECT_TRANSPARENT);

for (name of Object.keys(attrs)) {
	// omit functions, internal svelte properties and invalid attribute names
	if (typeof attrs[name] === 'function') continue;
	if (name[0] === '$' && name[1] === '$') continue; // faster than name.startsWith('$$')
	if (name === '' || INVALID_ATTR_NAME_CHAR_REGEX.test(name)) continue;

	var value = attrs[name];
	var lower = name.toLowerCase();

	if (lowercase) name = lower;

	// omit event handler attributes
	if (lower.length > 2 && lower.startsWith('on')) continue;

	if (is_input) {
		if (name === 'defaultvalue' || name === 'defaultchecked') {
			name = name === 'defaultvalue' ? 'value' : 'checked';
			if (attrs[name]) continue;
		}
	}

	attr_str += attr(name, value, is_html && is_boolean_attribute(name));
}
